import React from "react";
import { useState } from "react";
import { useParams } from "react-router-dom";
import axios from "axios"
import { useEffect } from "react";
import { Link as LinkRouter } from "react-router-dom" 


function DetailsPages(){
    const{id}=useParams()
    const [card, setCard] = useState([])
    const [cityname, setCityname] = useState("")
    const [image, setImage] = useState("")
    const [country, setCountry] = useState("")
    const [description, setDescription] = useState("")
    
    useEffect(() => {
        axios.get(`http://localhost:4000/api/cities/${id}`)
        .then(response => 
            setCard(response.data.response),
            setCityname(response.data.response.cities.cityname),
            setImage(response.data.response.cities.image),
            setCountry(response.data.response.cities.country),
            setDescription(response.data.response.cities.description))
    }, [])
    
    // useEffect(() => {
    //     setCard(cities.filter(data => data._id === id))
    // }, [])

    // let card = cities.filter(data => data._id === id)
    console.log(card);
    console.log(id);
    return(
        <div className="card-container">
            <div className="card">
                <div className="image">
                <img className="image-card" src= {image} alt="cities" />
                </div>
                <div>
                    <h2>{cityname}</h2>
                    <h3>{country}</h3>
                    <p>{description}</p>
                    <LinkRouter to={"/cities"}>
                        <button>Go Back!</button>
                    </LinkRouter>
                </div>
            </div>
        </div>
    );
}
export default DetailsPages
